mapper.select:
SELECT EXISTS (
    SELECT 1
    FROM admin_user_roles ur
    JOIN admin_role_permissions rp ON rp.role_id = ur.role_id
    JOIN admin_permissions p ON p.id = rp.permission_id
    WHERE ur.user_id = #{userId, javaType=java.util.UUID, jdbcType=OTHER}
      AND p.resource = #{resource}
      AND p.action = #{action}
)

SELECT EXISTS (
    SELECT 1
    FROM admin_resource_owners
    WHERE owner_id = #{ownerId, javaType=java.util.UUID, jdbcType=OTHER}
      AND resource = #{resource}
      AND resource_id = #{resourceId, javaType=java.util.UUID, jdbcType=OTHER}
)

mapper.insert:
INSERT INTO admin_user_roles(user_id, role_id) SELECT #{userId, javaType=java.util.UUID, jdbcType=OTHER}, id FROM admin_roles WHERE code IN
#{code}
ON CONFLICT DO NOTHING

mapper.update:
UPDATE media_assets
SET deleted_at = NOW()
WHERE id = #{id, javaType=java.util.UUID, jdbcType=OTHER}
